// // This module synchronously captures and stores the input data 'd' on the falling edge of the clock signal ('Clk'). If the reset signal ('Rst') is deasserted, the output 'q' is set to zero; otherwise, it updates to the value of 'd'.
module top_module(d, Clk, Rst, q);parameter DATAWIDTH = 8;

    input Clk, Rst;
    input [DATAWIDTH - 1:0] d;

    output reg [DATAWIDTH - 1:0] q;

    always @(posedge Clk) begin
        if(Rst)
            q <= 0;
        else
            q <= d;
    end

endmodule
